def count_up(n):
    for i in range(n):
        yield i

for val in count_up(5):
    print(val)      # 0, 1, 2, 3, 4

gen = count_up(5)
print(next(gen))    # 0
print(next(gen))    # 1

print(list(count_up(5)))    # [0, 1, 2, 3, 4]

def my_decorator(func):
    from functools import wraps

    @wraps(func)                    # preserves original function's metadata
    def wrapper(*args, **kwargs):
        print("before")
        result = func(*args, **kwargs)
        print("after")
        return result
    return wrapper

@my_decorator
def say_hello():
    print("hello")

say_hello()
# before
# hello
# after

import time
from functools import wraps

# Timer decorator
def timer(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"{func.__name__} took {end - start:.4f}s")
        return result
    return wrapper

@timer
def slow_sum(n):
    return sum(range(n))

slow_sum(1000000)   # slow_sum took 0.0312s  (time varies)

import functools

# Built-in cache decorator — remembers past results
@functools.lru_cache(maxsize=None)
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n-1) + fibonacci(n-2)

print(fibonacci(30))    # 832040  — fast because results are cached

